/// <summary>
///
/// </summary>
public void close()
{
    super();
    FormRun fr = element.args().caller();
    FormDataSource fds = fr.dataSource();
    ETGElevatorReceiptTable etgElevatorReceiptTable = fds.cursor();
    ETGElevatorReceiptSplitsItemTable etgElevatorReceiptSplitsItemTableLoc;

    etgElevatorReceiptTable.reread();

    select sum(SplitsPercentage) from etgElevatorReceiptSplitsItemTableLoc
        where etgElevatorReceiptSplitsItemTableLoc.ElevatorReceiptNumber == etgElevatorReceiptTable.ElevatorReceiptNumber;

    ttsbegin;

    etgElevatorReceiptTable.selectForUpdate(true);
    etgElevatorReceiptTable.SplitsPercentage = etgElevatorReceiptSplitsItemTableLoc.SplitsPercentage;
    etgElevatorReceiptTable.SplitsWeight = etgElevatorReceiptTable.GrainUnloadedWeight * ( etgElevatorReceiptTable.SplitsPercentage / 100);
    etgElevatorReceiptTable.NetWeight = etgElevatorReceiptTable.GrainUnloadedWeight - etgElevatorReceiptTable.DockageWeight - etgElevatorReceiptTable.SplitsWeight;
    etgElevatorReceiptTable.update();
    ttscommit;

    etgElevatorReceiptTable.write();
}

/// <summary>
///
/// </summary>
public void initValue()
{
    super();
    FormRun fr = element.args().caller();
    FormDataSource fds = fr.dataSource();
    ETGElevatorReceiptTable etgElevatorReceiptTable = fds.cursor();

    ETGElevatorReceiptSplitsItemTable.ElevatorReceiptNumber = etgElevatorReceiptTable.ElevatorReceiptNumber;

}

/// <summary>
///
/// </summary>
/// <returns></returns>
public int active()
{
    int ret;

    ret = super();
    FormRun fr = element.args().caller();
    FormDataSource fds = fr.dataSource();
    ETGElevatorReceiptTable etgElevatorReceiptTable = fds.cursor();
    ActionPane.enabled(etgElevatorReceiptTable.ETGElevatorReceiptStatus == ETGElevatorReceiptStatus::Draft);
    Grid.allowEdit(etgElevatorReceiptTable.ETGElevatorReceiptStatus == ETGElevatorReceiptStatus::Draft);
    return ret;
}

/// <summary>
/// Lookup for splits item 
/// </summary>
/// <param name = "_formControl"></param>
/// <param name = "_filterStr"></param>
public void lookup(FormControl _formControl, str _filterStr)
{
    //super(_formControl, _filterStr);
    Query query = new Query();
    QueryBuildDataSource queryBuildDataSource;
    QueryBuildRange queryBuildRange;
    SysTableLookup sysTableLookup =
SysTableLookup::newParameters(tableNum(ETGRateCardMaster), _formControl);

    sysTableLookup.addLookupField(fieldNum(ETGRateCardMaster,ItemId));
    sysTableLookup.addLookupField(fieldNum(ETGRateCardMaster,ProductName));

    queryBuildDataSource = query.addDataSource(tableNum(ETGRateCardMaster));
    queryBuildDataSource.company(ETGCanadaParameters::find().DefaultEntityForDocuments);
    FormRun fr = element.args().caller();
    FormDataSource fds = fr.dataSource();
    ETGElevatorReceiptTable etgElevatorReceiptTable = fds.cursor();
    ETGScaleTicketTable etgScaleTicketTable = ETGScaleTicketTable::findFromScaleTicketNumber(etgElevatorReceiptTable.ScaleTicketReferenceNumber);
    PurchAgreementHeader purchAgreementHeader = PurchAgreementHeader::findByAgreementId(etgScaleTicketTable.RefPurchAgreementNum,ETGCanadaParameters::find().DefaultEntityForDocuments);
    AgreementLine _agreementLine;
    InventTable inventTable;
    changecompany(ETGCanadaParameters::find().DefaultEntityForDocuments)
    {
        select firstonly _agreementLine
        where _agreementLine.Agreement == purchAgreementHeader.RecId;
        inventTable = InventTable::find(_agreementLine.ItemId);
    }
    queryBuildDataSource.addRange(fieldNum(ETGRateCardMaster,SubCommodity)).value(queryValue(inventTable.ETGSubCommodity));
    queryBuildDataSource.addRange(fieldNum(ETGRateCardMaster,RefRecId)).value(queryValue(_agreementLine.RecId));
    queryBuildDataSource.orderMode(OrderMode::GroupBy);
    queryBuildDataSource.addGroupByField(fieldNum(ETGRateCardMaster, ItemId));
    queryBuildDataSource.addGroupByField(fieldNum(ETGRateCardMaster, ProductName));

    sysTableLookup.parmQuery(query);
    sysTableLookup.performFormLookup();
}
